import numpy as np

def log1p_transform(x: np.ndarray) -> np.ndarray:
    return np.log1p(x)

def log1p_inverse(y: np.ndarray) -> np.ndarray:
    return np.expm1(y)

def box_cox_transform(x: np.ndarray, lam: float) -> np.ndarray:
    if abs(lam) < 1e-10:
        return np.log(x)
    return (np.power(x, lam) - 1.0) / lam

def box_cox_inverse(y: np.ndarray, lam: float) -> np.ndarray:
    if abs(lam) < 1e-10:
        return np.exp(y)
    return np.power(y * lam + 1.0, 1.0 / lam)
